CREATE OR REPLACE FUNCTION public.auto_seed_field_configs_on_company_create()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    PERFORM seed_account_field_configurations(NEW.id);
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.generate_account_id()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.account_id IS NULL OR NEW.account_id = '' THEN
        NEW.account_id := 'ACC-' || TO_CHAR(NOW(), 'YYYY') || '-' ||
                          LPAD(NEXTVAL('accounts_seq')::TEXT, 4, '0');
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.generate_amc_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.amc_number IS NULL OR NEW.amc_number = '' THEN
        NEW.amc_number := 'AMC-' || TO_CHAR(NOW(), 'YYYY') || '-' || 
                         LPAD((
                             SELECT COALESCE(MAX(CAST(SUBSTRING(amc_number FROM 'AMC-\d{4}-(\d+)') AS INTEGER)), 0) + 1
                             FROM amc_contracts 
                             WHERE amc_number ~ '^AMC-\d{4}-\d+$'
                             AND EXTRACT(YEAR FROM created_at) = EXTRACT(YEAR FROM NOW())
                         )::TEXT, 4, '0');
    END IF;

    IF TG_OP = 'UPDATE' THEN
        NEW.updated_at := NOW();
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.generate_contact_id()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  next_id INTEGER;
  new_contact_id VARCHAR(50);
BEGIN
  -- Get the next sequence number for this company
  SELECT COALESCE(MAX(CAST(SUBSTRING(contact_id FROM 6) AS INTEGER)), 0) + 1
  INTO next_id
  FROM contacts
  WHERE company_id = NEW.company_id;

  -- Generate the contact ID (e.g., CONT-001)
  new_contact_id := 'CONT-' || LPAD(next_id::TEXT, 3, '0');

  NEW.contact_id := new_contact_id;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.generate_entry_number(p_entry_type character varying, p_company_id uuid)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_prefix VARCHAR;
    v_year VARCHAR;
    v_next_number INTEGER;
    v_result VARCHAR;
BEGIN
    -- Set prefix based on entry type
    v_prefix := CASE
        WHEN p_entry_type = 'inward' THEN 'INW'
        WHEN p_entry_type = 'outward' THEN 'OUT'
        ELSE 'STK'
    END;

    -- Get current year
    v_year := TO_CHAR(CURRENT_DATE, 'YYYY');

    -- Get next number for this type and year (using table alias 'se')
    SELECT COALESCE(MAX(CAST(SPLIT_PART(se.entry_number, '-', 3) AS INTEGER)), 0) + 1
    INTO v_next_number
    FROM stock_entries se
    WHERE se.company_id = p_company_id
    AND se.entry_type = p_entry_type
    AND se.entry_number LIKE v_prefix || '-' || v_year || '-%';

    -- Format: INW-2025-001 or OUT-2025-001
    v_result := v_prefix || '-' || v_year || '-' || LPAD(v_next_number::TEXT, 3, '0');

    RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.generate_installation_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
  BEGIN
      IF NEW.installation_number IS NULL OR NEW.installation_number = '' THEN
          NEW.installation_number := 'INST-' || TO_CHAR(NOW(), 'YYYY') || '-' || LPAD(NEXTVAL('installation_number_seq')::TEXT, 6, '0');
      END IF;
      RETURN NEW;
  END;
  $function$

CREATE OR REPLACE FUNCTION public.log_account_activity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF TG_OP = 'INSERT' THEN
        INSERT INTO account_activities(account_id, user_id, activity_type, description, new_value)
        VALUES (NEW.id, auth.uid(), 'created', 'Account created', to_jsonb(NEW));
    ELSIF TG_OP = 'UPDATE' THEN
        INSERT INTO account_activities(account_id, user_id, activity_type, description, old_value, new_value)
        VALUES (NEW.id, auth.uid(), 'updated', 'Account updated', to_jsonb(OLD), to_jsonb(NEW));
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.reverse_product_stock()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_quantity_change INTEGER;
    v_stock_entry RECORD;
BEGIN
    -- Get stock entry details
    SELECT * INTO v_stock_entry FROM stock_entries WHERE id = OLD.stock_entry_id;

    -- Only reverse if stock entry was approved/completed
    IF v_stock_entry.status NOT IN ('approved', 'completed') THEN
        RETURN OLD;
    END IF;

    -- Calculate reverse quantity change
    IF v_stock_entry.entry_type = 'inward' THEN
        v_quantity_change := -OLD.quantity;
    ELSIF v_stock_entry.entry_type = 'outward' THEN
        v_quantity_change := OLD.quantity;
    END IF;

    -- Update product stock
    UPDATE products
    SET stock_quantity = stock_quantity + v_quantity_change
    WHERE id = OLD.product_id;

    RETURN OLD;
END;
$function$

CREATE OR REPLACE FUNCTION public.reverse_stock_entry()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_item RECORD;
    v_quantity_change INTEGER;
BEGIN
    -- Only reverse if entry was approved/completed
    IF OLD.status IN ('approved', 'completed') THEN

        -- Loop through all items and reverse the stock changes
        FOR v_item IN
            SELECT * FROM stock_entry_items WHERE stock_entry_id = OLD.id
        LOOP
            -- Calculate reverse quantity change
            IF OLD.entry_type = 'inward' THEN
                v_quantity_change := -v_item.quantity;
            ELSIF OLD.entry_type = 'outward' THEN
                v_quantity_change := v_item.quantity;
            ELSE
                v_quantity_change := 0;
            END IF;

            -- Update product stock (reverse the change)
            UPDATE products
            SET stock_quantity = COALESCE(stock_quantity, 0) + v_quantity_change,
                updated_at = NOW()
            WHERE id = v_item.product_id;

        END LOOP;

    END IF;

    RETURN OLD;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_account_modified_fields()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    NEW.last_modified_date := NOW();
    NEW.last_modified_by_id := auth.uid();
    RETURN NEW;
END;
$function$

