CREATE OR REPLACE FUNCTION public.update_company_user_count()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
  BEGIN
      IF TG_OP = 'INSERT' THEN
          UPDATE companies
          SET current_users = current_users + 1
          WHERE id = NEW.company_id;
          RETURN NEW;
      ELSIF TG_OP = 'DELETE' THEN
          UPDATE companies
          SET current_users = current_users - 1
          WHERE id = OLD.company_id;
          RETURN OLD;
      END IF;
      RETURN NULL;
  END;
  $function$

